export function deleteAllEmptyParents(node) {
    let parent = node.parent,
        entry = node,
        siblings_entry,
        children_entry = node.children;
    while (parent) {
        siblings_entry = parent.children;
        if (children_entry.length == 0) {
            let nodeIdxToRemove = searchNodeIdxByKey(siblings_entry, entry, 'value');
            removeNodeByIdx(siblings_entry, nodeIdxToRemove);
        }
        entry = parent;
        children_entry = entry.children;
        parent = parent.parent;
    }
}

function searchNodeIdxByKey(children, node, key) {
    var idx = -1;
    children.some((d, i) => {
        if (d[key] == node[key]) {
            idx = i;
            return true;
        }
    });
    return idx;
}
function removeNodeByIdx(nodes, idx) {
    if (idx > -1) {
        nodes.splice(idx, 1);
    }
}
